SELECT 
    (SELECT COALESCE(SUM(b.spent))), 0))
     FROM budget b 
     JOIN event e ON b.link_to_event = e.event_id
     WHERE e.event_date LIKE '2019%'
    ) - 
    (SELECT COALESCE(SUM(b.spent))), 0))
     FROM budget b 
     JOIN event e ON b.link_to_event = e.event_id
     WHERE e.event_date LIKE '2020%'
    )
) AS difference;

SELECT MIN(time) AS fastest_lap_time
FROM lapTimes
WHERE time IS NOT NULL;
